class Solution:
    def sumOddLengthSubarrays(self, arr):
        n = len(arr)
        total = 0
        for i in range(n):
            for j in range(i, n):
                if (j - i + 1) % 2 == 1:
                    total += sum(arr[i:j + 1])
        return total

