var sumOddLengthSubarrays = function(arr) {
    const n = arr.length;
    let total = 0;
    for (let i = 0; i < n; i++) {
        total += Math.floor(((i + 1) * (n - i) + 1) / 2) * arr[i];
    }
    return total;
};
